import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"Documentation structure","description":"Scope, ownership, and publication rules for Sovereign documentation.","frontmatter":{"title":"Documentation structure","description":"Scope, ownership, and publication rules for Sovereign documentation.","docSection":"contributors","docType":"policy","audiences":["contributor"]},"headers":[],"relativePath":"documentation-structure.md","filePath":"documentation-structure.md"}'),n={name:"documentation-structure.md"};function s(d,e,r,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="documentation-structure" tabindex="-1">Documentation structure <a class="header-anchor" href="#documentation-structure" aria-label="Permalink to &quot;Documentation structure&quot;">​</a></h1><p>Sovereign keeps product education, task-oriented guides, current technical reference, design decisions, and project operations separate. Each factual topic has one canonical owner; other pages summarize it and link to that owner.</p><h2 id="content-classes" tabindex="-1">Content classes <a class="header-anchor" href="#content-classes" aria-label="Permalink to &quot;Content classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Class</th><th>Purpose</th><th>Canonical location</th><th>Published</th></tr></thead><tbody><tr><td>Product</td><td>Explain Sovereign&#39;s value, capabilities, apps, and direction</td><td><code>product/</code>, <code>product-roadmap.md</code>, <code>instances.md</code></td><td>Yes</td></tr><tr><td>Get started</td><td>Short, sequential paths for users, operators, and app developers</td><td><code>get-started/</code></td><td>Yes</td></tr><tr><td>Audience hubs</td><td>Route each audience to canonical guides and references</td><td><code>guides/</code></td><td>Yes</td></tr><tr><td>Technical reference</td><td>Describe current behavior, configuration, APIs, and architecture</td><td>Named root references and <code>plugins/</code></td><td>Yes</td></tr><tr><td>Research</td><td>Explore open-ended questions before a design is proposed</td><td><code>research/</code></td><td>No</td></tr><tr><td>Decisions</td><td>Record accepted and proposed cross-cutting designs</td><td><code>rfcs/</code></td><td>Yes, with status</td></tr><tr><td>Project operations</td><td>Track tasks, plans, findings, and internal coordination</td><td><code>epics/</code>, <code>adhoc/</code>, roadmap and planning files</td><td>No</td></tr></tbody></table><h2 id="ownership-rules" tabindex="-1">Ownership rules <a class="header-anchor" href="#ownership-rules" aria-label="Permalink to &quot;Ownership rules&quot;">​</a></h2><ul><li>Product pages explain outcomes and avoid reproducing configuration or API reference material.</li><li>Get-started pages stop after the first successful path and link to the canonical reference for complete behavior.</li><li>Audience hubs are indexes. They should not become second copies of guides.</li><li>Technical references describe implemented behavior. Future designs belong in RFCs and must not be presented as shipped functionality.</li><li>RFCs explain decisions and proposals. They do not replace current reference documentation after implementation.</li><li>Research docs explore a question before it has a concrete design — findings, options, and a recommendation, not a commitment. A research doc precedes an RFC for open-ended topics; it is not deleted once an RFC lands, and not every research doc graduates to one (a documented &quot;not now&quot; is a valid outcome). See <code>docs/research/README.md</code>.</li><li>The public product roadmap describes themes. <code>ROADMAP.md</code> and <code>epics/</code> remain the private engineering queue and source of task status.</li></ul><h2 id="technical-reference-metadata" tabindex="-1">Technical-reference metadata <a class="header-anchor" href="#technical-reference-metadata" aria-label="Permalink to &quot;Technical-reference metadata&quot;">​</a></h2><p>Canonical root references keep stable filenames and URLs while declaring their ownership in frontmatter:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">docSection</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">operators</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">docType</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">guide</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">audiences</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">operator</span></span></code></pre></div><p><code>docSection</code> controls the primary navigation group and must be one of <code>operators</code>, <code>app-developers</code>, <code>architecture-security</code>, or <code>contributors</code>. <code>docType</code> describes how the page should be maintained and must be <code>guide</code>, <code>reference</code>, or <code>policy</code>. <code>audiences</code> records every audience expected to use the page and may contain <code>user</code>, <code>operator</code>, <code>app-developer</code>, or <code>contributor</code>.</p><p>A page has one primary section even when several audiences use it. For example, <code>security.md</code> belongs to Architecture &amp; Security while serving all four audiences. Metadata expresses ownership without moving established files or changing their public and GitHub URLs.</p><h2 id="publication-boundary" tabindex="-1">Publication boundary <a class="header-anchor" href="#publication-boundary" aria-label="Permalink to &quot;Publication boundary&quot;">​</a></h2><p>The docs site uses the explicit policy in <code>apps/docs/.vitepress/publication.ts</code>. Public directories and canonical root references are opted in there. Every other Markdown file is excluded from page generation and local search automatically.</p><p>Adding a link to navigation does not make a document public. A new public content class or root reference requires a deliberate publication-policy change, which keeps internal notes from becoming public merely because they live under <code>docs/</code>.</p><h2 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h2><p>Long-standing root references such as <code>self-hosting.md</code>, <code>plugin-development.md</code>, and <code>architecture.md</code> keep their source paths and URLs. Repository tests, source comments, RFCs, package documentation, and external GitHub links depend on those locations. Their audience ownership is expressed through navigation and this contract rather than disruptive file moves.</p><p>Audience indexes live in <code>guides/</code>, while explicit VitePress rewrites preserve their established <code>/docs/</code> public URLs. Source organization can therefore stay clear without invalidating bookmarks, search results, or inbound links.</p>`,17)])])}const m=t(n,[["render",s]]);export{h as __pageData,m as default};
